// Parâmetro obrigatório
Route::get('/usuarios/{id}', function (string $id) {
    return "Usuário: {$id}";
});

// Parâmetro opcional com valor padrão
Route::get('/posts/{slug?}', function (string $slug = 'todos') {
    return "Posts: {$slug}";
});

// Múltiplos parâmetros
Route::get('/cursos/{curso}/licoes/{licao}', function (string $curso, string $licao) {
    return "Curso: {$curso}, Lição: {$licao}";
});
